    'info.terms.s1':              { ko: '무공해차 구매보조금 신청·조회',             en: 'ZEV purchase subsidy application and inquiry' },
    'info.terms.s2':              { ko: '충전 인프라 정보 검색 및 충전 카드 관리',    en: 'Charging infrastructure search and card management' },
