    'info.terms.s5':              { ko: '공공 데이터 다운로드 및 정책 정보 제공',     en: 'Public data download and policy information' },
    'info.terms.a8':              { ko: '<strong>제8조 (서비스 이용 시간)</strong> 서비스의 이용은 공단의 업무상 또는 기술상 특별한 지장이 없는 한 연중무휴 1일 24시간 운영을 원칙으로 합니다. 단, 정기 점검 시간(매월 첫째 화요일 02:00~04:00)에는 일시 중단될 수 있습니다',
                                    en: '<strong>Article 8 (Service Hours)</strong> Services operate 24/7 year-round in principle, except for business or technical issues. Service may pause during scheduled maintenance (first Tuesday monthly, 02:00-04:00).' },
    'info.terms.h3.4':            { ko: '제4장 회원의 의무',                        en: 'Chapter 4 Member Obligations' },
    'info.terms.a9':              { ko: '<strong>제9조 (회원의 의무)</strong> 회원은 다음 행위를 하여서는 안 됩니다.',
                                    en: '<strong>Article 9 (Member Obligations)</strong> Members shall not engage in the following.' },
    'info.terms.d8':              { ko: '신청 또는 변경 시 허위 내용의 등록',        en: 'Registration of false information at application or change' },
