    'info.terms.d13':             { ko: '보조금을 부정 수령하거나 부적정하게 신청하는 행위',
                                    en: 'Unlawful subsidy receipt or improper application' },
    'info.terms.a10':             { ko: '<strong>제10조 (계정 정보의 관리)</strong> 회원의 ID와 비밀번호 관리 책임은 회원 본인에게 있으며, 이를 제3자가 이용하도록 하여서는 안 됩니다. 5회 이상 비밀번호 오입력 시 30분간 로그인이 제한됩니다.',
                                    en: '<strong>Article 10 (Account Management)</strong> Members are responsible for managing their ID/password and shall not allow third-party use. After 5+ incorrect password attempts, login is restricted for 30 minutes.' },
    'info.terms.h3.5':            { ko: '제5장 서비스 제공의 중지·해지',             en: 'Chapter 5 Service Suspension/Termination' },
    'info.terms.a11':             { ko: '<strong>제11조 (서비스 제공의 중지)</strong> 공단은 다음 각 호에 해당하는 경우 서비스 제공을 중지할 수 있습니다.',
                                    en: '<strong>Article 11 (Service Suspension)</strong> The Corporation may suspend services in the following cases.' },
    'info.terms.d14':             { ko: '서비스 설비의 보수 등 공사로 인한 부득이한 경우',
                                    en: 'Unavoidable cases due to maintenance work on service facilities' },
